// TestRegression_UnintendedNonLibraryAnalyzerExecution tests that non-application
// analyzers (like OS packaging analyzers) don't execute during library-only scans.
func TestRegression_UnintendedNonLibraryAnalyzerExecution(t *testing.T) {
	t.Run("Non-library analyzers should not execute in library analysis", func(t *testing.T) {
		// Create a npm package-lock.json to ensure we're analyzing with library analyzers
		npmLockContent := []byte(`{
  "name": "test-app",
  "version": "1.0.0",
  "lockfileVersion": 1,
  "requires": true,
  "dependencies": {
    "lodash": {
      "version": "4.17.15",
      "resolved": "https://registry.npmjs.org/lodash/-/lodash-4.17.15.tgz"
    }
  }
}`)

		libFilemap := map[string]struct {
			Contents []byte
			Filemode os.FileMode
		}{
			"package-lock.json": {
				Contents: npmLockContent,
				Filemode: 0644,
			},
		}

		// Analyze with disabledAnalyzers - OS package analyzers should be disabled
		disabledAnalyzers := []analyzer.Type{
			analyzer.TypeAlpine,
			analyzer.TypeAlma,
			analyzer.TypeAmazon,
			analyzer.TypeDebian,
			analyzer.TypePhoton,
			analyzer.TypeCentOS,
			analyzer.TypeFedora,
			analyzer.TypeOracle,
			analyzer.TypeRedHatBase,
			analyzer.TypeRocky,
			analyzer.TypeSUSE,
			analyzer.TypeUbuntu,
			analyzer.TypeApk,
			analyzer.TypeDpkg,
			analyzer.TypeRpm,
			analyzer.TypeApkCommand,
			analyzer.TypeYaml,
			analyzer.TypeTOML,
			analyzer.TypeJSON,
			analyzer.TypeDockerfile,
			analyzer.TypeHCL,
			analyzer.TypeSecret,
		}

		anal := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)

		ctx := context.Background()
		for path, f := range libFilemap {
			var wg sync.WaitGroup
			result := new(analyzer.AnalysisResult)
			err := anal.AnalyzeFile(
				ctx,
				&wg,
				semaphore.NewWeighted(1),
				result,
				"",
				path,
				&DummyFileInfo{size: int64(len(f.Contents)), filemode: f.Filemode},
				func() (dio.ReadSeekCloserAt, error) { return dio.NopCloser(bytes.NewReader(f.Contents)), nil },
				nil,
				analyzer.AnalysisOptions{Offline: true},
			)
			wg.Wait()

			if err != nil {
				t.Logf("Analysis error (may be expected): %v", err)
			}

			// Should have detected npm applications/libraries when disabled analyzers don't interfere
			if result.Applications == nil || len(result.Applications) == 0 {
				t.Logf("INFO: No applications detected from package-lock.json. This may indicate an issue with library analysis.")
			}
		}
	})
}
